        }
        
        return START_NOT_STICKY
    }
    
    private fun validateIntent(intent: Intent): Boolean {
        val packageName = intent.`package` ?: return false
        val signatureHash = getPackageSignatureHash(packageName)
        return signatureHash != null && isValidSignature(signatureHash)
