    private fun getPackageSignatureHash(packageName: String): String? {
        return try {
            val packageInfo = packageManager.getPackageInfo(packageName, PackageManager.GET_SIGNATURES)
            packageInfo.signatures?.firstOrNull()?.toByteArray()?.let { 
                val md = MessageDigest.getInstance("SHA")
                md.update(it)
                Base64.encodeToString(md.digest(), Base64.NO_WRAP)
            }
        } catch (e: Exception) {
            Log.e(TAG, "Failed to get package signature", e)
            null
        }
    }
    
    private fun isValidSignature(signatureHash: String): Boolean {
        val allowedSignatures = setOf(
            "YOUR_APP_SIGNATURE_HASH_1",
            "YOUR_APP_SIGNATURE_HASH_2"
        )
        return signatureHash in allowedSignatures
    }
    
